<!doctypehtml><html lang=en><meta charset=UTF-8><meta content="width=device-width,initial-scale=1"name=viewport><title>UPSC Video</title><link href=style.css rel=stylesheet><div class=container><header><img alt=company_logo height=55px src=https://cybertron7.in/images/black_logo.png width=50px><h1>UPSC Video</h1><p>Curated YouTube videos for your UPSC preparation</header><div class=filter-section><input id=searchInput placeholder="Search videos..."> <select id=categorySelect><option value="">All Categories</select> <select id=sortSelect><option value=watched>Sort by Watched<option value=title>Sort by Title<option value=date>Sort by Date</select> <button id=clearWatched>Clear Watched</button></div><div id=toast class=toast></div><section class=upload-section><form action=https://cybertron7.in/RajnitiKutir/upload.awc id=uploadForm method=POST><input id=videoLink placeholder="Paste YouTube video link"name=videoLink required type=url> <button type=submit>Add Video</button></form></section><section class=video-list><h2>Video List</h2><div id=videoContainer></div><div id=pagination></div></section><div id=pagination><button id=prevPage disabled>Previous</button> <button id=nextPage>Next</button></div></div><div id=loader class=loader></div><script src=script.js></script>